api-reference_514.content:
```typescript
type Filter = {
  /**
   * Field name to filter on
   */
  [field: string]: FilterValue | FilterOperator;
};

type FilterValue = string | number | boolean | null;

interface FilterOperator {
  $eq?: FilterValue;      // Equal to
  $ne?: FilterValue;      // Not equal to
  $gt?: number;           // Greater than
  $gte?: number;          // Greater than or equal
  $lt?: number;           // Less than
  $lte?: number;          // Less than or equal
  $in?: FilterValue[];    // In array
  $nin?: FilterValue[];   // Not in array
  $exists?: boolean;      // Field exists
  $contains?: string;     // String contains (case-insensitive)
  $startsWith?: string;   // String starts with
  $endsWith?: string;     // String ends with
}

interface LogicalOperator {
  $and?: Filter[];        // All conditions must match
  $or?: Filter[];         // Any condition must match
  $not?: Filter;          // Negate condition
}
```

**Example Usage:**

```typescript
// Simple equality filter
const simpleFilter: Filter = {
  category: 'technical',
  status: 'published',
};

// Complex filter with operators
const complexFilter: Filter = {
  $and: [
    { category: { $in: ['technical', 'tutorial'] } },
    { score: { $gte: 0.8 } },
    { timestamp: { $gt: Date.now() - 86400000 } }, // Last 24 hours
    {
      $or: [
        { author: 'admin' },
        { verified: true },
      ],
    },
  ],
};

// Search with filter
const results = await collection.search({
  vector: queryVector,
  k: 20,
  filter: complexFilter,
  minScore: 0.7,
});
```

