api-reference_2881.content:
```typescript
import { Module } from 'dspy.ts';

/**
 * Abstract base class for all DSPy modules.
 * Modules encapsulate LLM operations with defined input/output signatures.
 */
abstract class Module<TInput, TOutput> {
  /**
   * Module name for identification
   */
  readonly name: string;

  /**
   * Input/output signature
   */
  readonly signature: Signature;

  /**
   * Language model driver
   */
  protected lm: LMDriver;

  /**
   * Create a new module
   * @param config - Module configuration
   */
  constructor(config: ModuleConfig);

  /**
   * Execute the module with input
   * @param input - Input matching signature input fields
   * @returns Promise resolving to output matching signature output fields
   */
  abstract run(input: TInput): Promise<TOutput>;

  /**
   * Validate input against signature
   * @param input - Input to validate
   * @returns Validation result
   */
  protected validateInput(input: TInput): ValidationResult;

  /**
   * Validate output against signature
   * @param output - Output to validate
   * @returns Validation result
   */
  protected validateOutput(output: TOutput): ValidationResult;

  /**
   * Get module demonstrations (few-shot examples)
   * @returns Array of input/output examples
   */
  getDemos(): Demo<TInput, TOutput>[];

  /**
   * Set module demonstrations
   * @param demos - Array of demonstrations
   */
  setDemos(demos: Demo<TInput, TOutput>[]): void;

  /**
   * Clone the module with optional modifications
   * @param overrides - Optional configuration overrides
   */
  clone(overrides?: Partial<ModuleConfig>): this;

  /**
   * Save module state to JSON
   */
  save(): ModuleState;

  /**
   * Load module state from JSON
   * @param state - Previously saved state
   */
  load(state: ModuleState): void;
}
```

