api-reference_3206.content:
ReAct (Reasoning + Acting) module for tool-augmented reasoning.

```typescript
import { ReAct, Tool } from 'dspy.ts';

class ReAct<TInput, TOutput> extends Module<TInput, TOutput> {
  /**
   * Create a ReAct module
   * @param signature - Base signature
   * @param tools - Available tools
   * @param config - Optional configuration
   */
  constructor(
    signature: string | Signature,
    tools: Tool[],
    config?: ReActConfig
  );

  /**
   * Run with interleaved reasoning and tool use
   * @param input - Input fields
   * @returns Final output after reasoning and acting
   */
  async run(input: TInput): Promise<TOutput>;

  /**
   * Get the trace of reasoning steps
