import { BootstrapFewShot } from 'dspy.ts';

class BootstrapFewShot<TInput, TOutput> {
  /**
   * Create a BootstrapFewShot optimizer
   * @param config - Optimizer configuration
   */
  constructor(config: BootstrapConfig);

  /**
   * Compile a module with bootstrapped demonstrations
   * @param module - Module to optimize
   * @param trainset - Training examples
   * @param metric - Evaluation metric function
   * @returns Optimized module
   */
  async compile(
    module: Module<TInput, TOutput>,
    trainset: Example<TInput, TOutput>[],
