```typescript
interface TaskScheduler {
  schedule(tasks: TaskDefinition[], agents: AgentState[]): TaskAssignment[];
}

class FIFOScheduler implements TaskScheduler {
  schedule(tasks: TaskDefinition[], agents: AgentState[]): TaskAssignment[] {
    return tasks.map((task, i) => ({
      task: task.id,
      agent: agents[i % agents.length].id
    }));
  }
}

class PriorityScheduler implements TaskScheduler {
  schedule(tasks: TaskDefinition[], agents: AgentState[]): TaskAssignment[] {
    const sorted = tasks.sort((a, b) =>
      getPriorityValue(b.priority) - getPriorityValue(a.priority)
    );
    return this.assignByPriority(sorted, agents);
  }
}

class DeadlineScheduler implements TaskScheduler {
  schedule(tasks: TaskDefinition[], agents: AgentState[]): TaskAssignment[] {
    const sorted = tasks.sort((a, b) =>
      (a.constraints.deadline?.getTime() || Infinity) -
      (b.constraints.deadline?.getTime() || Infinity)
    );
    return this.assignByDeadline(sorted, agents);
  }
}

// Context that uses strategy
class TaskCoordinator {
  private scheduler: TaskScheduler;

  setScheduler(strategy: TaskSchedulingStrategy) {
    switch (strategy) {
      case 'fifo': this.scheduler = new FIFOScheduler(); break;
      case 'priority': this.scheduler = new PriorityScheduler(); break;
      case 'deadline': this.scheduler = new DeadlineScheduler(); break;
    }
  }

  scheduleTasks(tasks: TaskDefinition[], agents: AgentState[]) {
    return this.scheduler.schedule(tasks, agents);
  }
}
