export class MCPAuthManager {
  private static instance: MCPAuthManager;
  private tokens: Map<string, TokenInfo>;
  private tokenStorage: Storage;

  private constructor(storage?: Storage) {
    this.tokens = new Map<string, TokenInfo>();
    this.tokenStorage = storage || this.createDefaultStorage();
    this.loadTokens();
  }

  public static getInstance(storage?: Storage): MCPAuthManager {
    if (!MCPAuthManager.instance) {
      MCPAuthManager.instance = new MCPAuthManager(storage);
    }
    return MCPAuthManager.instance;
  }

  public setToken(serverId: string, token: string, expiresAt?: Date | null): void {
    this.tokens.set(serverId, { token, expiresAt: expiresAt || null });
    this.saveTokens();
  }

  public async getToken(serverId: string): Promise<string | null> {
    if (this.tokens.has(serverId)) {
      const tokenInfo = this.tokens.get(serverId)!;
      if (this.isTokenExpired(serverId)) {
        if (tokenInfo.refreshToken) {
          return await this.refreshToken(serverId, tokenInfo.refreshToken);
        }
        this.tokens.delete(serverId);
        return null;
      }
      return tokenInfo.token;
    }
    return null;
  }
}
