interface RequestMessage {
  id: string;
  type: string;
  payload: any;
  correlationId?: string;
}

interface ResponseMessage {
  id: string;
  type: string;
  payload: any;
  relatedTo: string;  // References request ID
}

class MessageCorrelator {
  private pendingRequests = new Map<string, {
    resolve: Function;
    reject: Function;
    timeout: NodeJS.Timeout;
  }>();

  async request(message: RequestMessage, timeoutMs = 5000): Promise<ResponseMessage> {
    return new Promise((resolve, reject) => {
      const timeout = setTimeout(() => {
        this.pendingRequests.delete(message.id);
        reject(new Error('Request timeout'));
      }, timeoutMs);

      this.pendingRequests.set(message.id, { resolve, reject, timeout });
      this.send(message);
    });
  }

  handleResponse(response: ResponseMessage) {
    const pending = this.pendingRequests.get(response.relatedTo);
    if (pending) {
      clearTimeout(pending.timeout);
      this.pendingRequests.delete(response.relatedTo);
      pending.resolve(response);
    }
  }
}
