class StreamingServer {
  constructor(server) {
    this.wss = new WebSocket.Server({ server });
    this.clients = new Map();

    this.wss.on('connection', (ws, req) => {
      const clientId = this.generateClientId();
      this.clients.set(clientId, { ws, subscriptions: new Set() });

      ws.on('message', (message) => this.handleMessage(clientId, message));
      ws.on('close', () => this.handleDisconnect(clientId));
    });
  }

  async streamResponse(clientId, generator) {
    const client = this.clients.get(clientId);
    if (!client) return;

    for await (const chunk of generator) {
      if (client.ws.readyState === WebSocket.OPEN) {
        client.ws.send(JSON.stringify({
          type: 'stream',
          data: chunk,
          timestamp: Date.now()
        }));
      }
    }

    client.ws.send(JSON.stringify({ type: 'stream_end' }));
  }

  broadcast(message, filter = () => true) {
    for (const [id, client] of this.clients) {
      if (filter(id, client) && client.ws.readyState === WebSocket.OPEN) {
        client.ws.send(JSON.stringify(message));
      }
    }
  }
}
