class ClientStateModel {
  constructor() {
    this.states = new Map();
  }

  initializeClient(clientId) {
    this.states.set(clientId, {
      isAuthenticated: false,
      sessionId: null,
      lastActivity: Date.now(),
      permissions: [],
      metadata: {}
    });
  }

  async updateSessionState(clientId, updates) {
    const state = this.states.get(clientId);
    if (!state) return false;

    Object.assign(state, updates, { lastActivity: Date.now() });
    await this.persistState(clientId, state);
    return true;
  }

  getState(clientId) {
    return this.states.get(clientId) || null;
  }

  async persistState(clientId, state) {
    // Persist to storage for recovery
    await storage.set(`client:${clientId}`, JSON.stringify(state));
  }

  async restoreState(clientId) {
    const stored = await storage.get(`client:${clientId}`);
    if (stored) {
      this.states.set(clientId, JSON.parse(stored));
      return true;
    }
    return false;
  }
}
