export type ConsistencyLevel =
  | 'strong'    // Strong consistency
  | 'eventual'  // Eventual consistency
  | 'weak'      // Weak consistency
  | 'session';  // Session consistency

export interface SwarmMemory {
  namespace: string;
  partitions: MemoryPartition[];
  permissions: MemoryPermissions;
  persistent: boolean;
  backupEnabled: boolean;
  distributed: boolean;
  consistency: ConsistencyLevel;
  cacheEnabled: boolean;
  compressionEnabled: boolean;
}

class DistributedMemory {
  private consistency: ConsistencyLevel;
  private replicas: Map<string, MemoryReplica>;

  async write(key: string, value: any): Promise<void> {
    switch (this.consistency) {
      case 'strong':
        // Write to all replicas before returning
        await Promise.all(
          Array.from(this.replicas.values()).map(r => r.write(key, value))
        );
        break;
      case 'eventual':
        // Write to primary, propagate async
        await this.primaryReplica.write(key, value);
        this.propagateAsync(key, value);
        break;
      case 'session':
        // Write to session-local replica
        await this.sessionReplica.write(key, value);
        break;
    }
  }

  async read(key: string): Promise<any> {
    switch (this.consistency) {
      case 'strong':
        // Read from quorum
        return await this.readQuorum(key);
      case 'eventual':
        // Read from any replica
        return await this.readAny(key);
      case 'session':
        // Read from session replica first
        return await this.sessionReplica.read(key) ?? await this.readAny(key);
    }
  }
}
