type LoadBalancingStrategy =
  | 'work-stealing'  // Agents steal work from busy agents
  | 'work-sharing'   // Work is proactively shared
  | 'centralized'    // Central dispatcher
  | 'distributed'    // Distributed load balancing
  | 'predictive'     // Predict and prevent overload
  | 'reactive';      // React to overload conditions

class WorkStealingBalancer {
  private agents: Map<string, AgentState>;
  private taskQueues: Map<string, TaskId[]>;

  async balance() {
    const overloaded = this.findOverloadedAgents();
    const idle = this.findIdleAgents();

    for (const idleAgent of idle) {
      for (const busyAgent of overloaded) {
        const stolenTask = this.stealTask(busyAgent, idleAgent);
        if (stolenTask) {
          await this.reassignTask(stolenTask, idleAgent);
          break;
        }
      }
    }
  }

  private findOverloadedAgents(): AgentState[] {
    return Array.from(this.agents.values())
      .filter(a => a.workload > 0.8);
  }

  private findIdleAgents(): AgentState[] {
    return Array.from(this.agents.values())
      .filter(a => a.workload < 0.3 && a.status === 'idle');
  }

  private stealTask(from: AgentState, to: AgentState): TaskId | null {
    const queue = this.taskQueues.get(from.id.id) || [];
    // Steal lowest priority task that to-agent can handle
    for (let i = queue.length - 1; i >= 0; i--) {
      const task = this.getTask(queue[i]);
      if (this.canHandle(to, task)) {
        return queue.splice(i, 1)[0];
      }
    }
    return null;
  }
}
