export type AccessLevel =
  | 'private'   // Only owner can access
  | 'team'      // Team members can access
  | 'swarm'     // All swarm agents can access
  | 'public'    // Publicly accessible
  | 'system';   // System-level access

export interface MemoryPermissions {
  read: AccessLevel;
  write: AccessLevel;
  delete: AccessLevel;
  share: AccessLevel;
}

export interface AgentConfig {
  permissions: string[];
  trustedAgents: AgentId[];
}

class PermissionChecker {
  canAccess(agent: AgentState, resource: MemoryEntry, action: keyof MemoryPermissions): boolean {
    const requiredLevel = resource.accessLevel;
    const permissions = resource.permissions || { read: 'private', write: 'private', delete: 'private', share: 'private' };

    const actionLevel = permissions[action];

    switch (actionLevel) {
      case 'private':
        return resource.owner.id === agent.id.id;
      case 'team':
        return this.isTeamMember(agent, resource.owner);
      case 'swarm':
        return agent.id.swarmId === resource.owner.swarmId;
      case 'public':
        return true;
      case 'system':
        return agent.config.permissions.includes('system');
      default:
        return false;
    }
  }
}
