}

impl RuleEngine {
    pub fn evaluate(&self, event: Event) -> Vec<Action> {
        // 1. Find matching rules
        let matching = self.rules.iter()
            .filter(|r| r.matches(&event, &self.context))
            .collect();

        // 2. Resolve conflicts by priority
        let resolved = self.resolve_conflicts(matching);

        // 3. Return actions
        resolved.iter().flat_map(|r| &r.actions).collect()
    }
}
```

