import {
  ChainOfThought,
  BootstrapFewShot,
  configureLM,
  OpenAILM
} from 'dspy.ts';

const lm = new OpenAILM({ apiKey: process.env.OPENAI_API_KEY });
await lm.init();
configureLM(lm);

// Create module
const qaModule = new ChainOfThought({
  name: 'QA',
  signature: {
    inputs: [
      { name: 'context', type: 'string', required: true },
      { name: 'question', type: 'string', required: true }
    ],
    outputs: [
      { name: 'answer', type: 'string', required: true }
    ]
  }
});

// Define metric
const exactMatch = (input, output, expected) => {
  return output.answer.toLowerCase().trim() ===
         expected?.answer.toLowerCase().trim() ? 1.0 : 0.0;
};

// Create optimizer
const optimizer = new BootstrapFewShot(exactMatch, {
  maxBootstrappedDemos: 4,
  maxLabeledDemos: 8
});

// Training data
const trainset = [
  {
    input: { context: 'Paris is the capital of France.', question: 'What is the capital of France?' },
    output: { answer: 'Paris' }
  },
  // ... more examples
];

// Optimize
const optimizedModule = await optimizer.compile(qaModule, trainset);

// Use optimized module
const result = await optimizedModule.run({
  context: 'Berlin is the capital of Germany.',
  question: 'What is the capital of Germany?'
});
