// BAD: No memory limits
class BadMemoryStore {
  private data: any[] = [];

  store(item: any) {
    this.data.push(item);  // Grows forever!
  }
}

// GOOD: Implement eviction policies
class BoundedMemoryStore {
  private data: Map<string, { value: any; timestamp: number }> = new Map();
  private maxSize: number;

  constructor(maxSize: number = 10000) {
    this.maxSize = maxSize;
  }

  store(key: string, item: any): void {
    if (this.data.size >= this.maxSize) {
      this.evictOldest();
    }

    this.data.set(key, {
      value: item,
      timestamp: Date.now()
    });
  }

  private evictOldest(): void {
    let oldestKey = '';
    let oldestTime = Infinity;

    for (const [key, entry] of this.data) {
      if (entry.timestamp < oldestTime) {
        oldestTime = entry.timestamp;
        oldestKey = key;
      }
    }

    if (oldestKey) {
      this.data.delete(oldestKey);
    }
  }
}
