// SLOW: Pure JavaScript similarity computation
function cosineSimilarityJS(a: number[], b: number[]): number {
  let dot = 0, normA = 0, normB = 0;
  for (let i = 0; i < a.length; i++) {
    dot += a[i] * b[i];
    normA += a[i] * a[i];
    normB += b[i] * b[i];
  }
  return dot / (Math.sqrt(normA) * Math.sqrt(normB));
}

// FAST: Use WASM when available (10x faster)
import { hasWasmSupport, wasmCosineSimilarity } from 'ruvector/wasm';

function cosineSimilarity(a: Float32Array, b: Float32Array): number {
  if (hasWasmSupport()) {
    return wasmCosineSimilarity(a, b);  // 10x faster
  }
  return cosineSimilarityJS(Array.from(a), Array.from(b));
}
