// MicroLoRA: Minimal per-request adaptation
pub struct MicroLoRA {
    delta_w: SparseMatrix,  // Typically rank 1-2
    learning_rate: f32,     // Very small: 1e-5
    decay: f32,             // Fast decay: 0.99
}

impl MicroLoRA {
    pub fn adapt(&mut self, context: &Context, feedback: f32) {
        // Sparse update - only modify relevant dimensions
        let gradient = self.compute_sparse_gradient(context);
        self.delta_w.axpy(self.learning_rate * feedback, &gradient);
        self.delta_w.scale(self.decay);  // Prevent accumulation
    }
}
```

