TRM enables recursive reasoning with minimal overhead through distilled, task-specific models.

```rust
pub struct TinyRecursiveModel {
    base_model: CompactTransformer,
    recursion_depth: usize,
    output_projection: Linear,
}

impl TinyRecursiveModel {
    pub fn reason(&self, input: &Tensor, max_steps: usize) -> Tensor {
        let mut state = self.base_model.encode(input);

        for _ in 0..max_steps.min(self.recursion_depth) {
            let reasoning = self.base_model.forward(&state);
            state = state + reasoning;  // Residual accumulation

            if self.should_terminate(&state) {
                break;
            }
        }

        self.output_projection.forward(&state)
    }
}
