app.post('/webhook/fireflies', async (c) => {
  // Verify webhook signature
  const signature = c.req.header('X-Fireflies-Signature')
  const body = await c.req.json<FirefliesWebhook>()

  if (!verifySignature(body, signature)) {
    return c.json({ error: 'Invalid signature' }, 401)
  }

  // Process based on event type
  switch (body.event) {
    case 'transcription.completed':
      await processTranscript(body.data)
      break
    case 'meeting.started':
      await logMeetingStart(body.data)
      break
    case 'meeting.ended':
      await logMeetingEnd(body.data)
      break
  }

  return c.json({ status: 'processed' })
})

export default app
