async function extractActionItems(transcript: TranscriptSegment[]): Promise<ActionItem[]> {
  const fullText = transcript.map(s => `${s.speaker}: ${s.text}`).join('\n')

  const response = await openai.chat.completions.create({
    model: 'gpt-4',
    messages: [
      {
        role: 'system',
        content: 'Extract action items from the meeting transcript. Return as JSON array with fields: task, assignee, deadline (if mentioned).'
      },
      { role: 'user', content: fullText }
    ]
  })

  return JSON.parse(response.choices[0].message.content)
}

async function generateSummary(transcript: TranscriptSegment[]): Promise<string> {
  const fullText = transcript.map(s => `${s.speaker}: ${s.text}`).join('\n')

  const response = await openai.chat.completions.create({
    model: 'gpt-4',
    messages: [
      {
        role: 'system',
        content: 'Summarize this meeting transcript in 3-5 bullet points covering key decisions and discussions.'
      },
      { role: 'user', content: fullText }
    ]
  })

  return response.choices[0].message.content
}
