```typescript
// supabase/functions/agent-orchestrator/index.ts
import { serve } from "https://deno.land/std@0.168.0/http/server.ts"
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2'
import { ChatOpenAI } from "https://esm.sh/langchain/chat_models/openai"
import { HumanMessage, SystemMessage } from "https://esm.sh/langchain/schema"

interface AgentTask {
  taskId: string
  agentId: string
  action: string
  parameters: Record<string, any>
}

serve(async (req) => {
  const supabase = createClient(
    Deno.env.get('SUPABASE_URL')!,
    Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
  )

  const { taskId, agentId, action, parameters } = await req.json() as AgentTask

  // Get agent configuration
  const { data: agent } = await supabase
    .from('agents')
    .select('*')
    .eq('id', agentId)
    .single()

  // Get task details
  const { data: task } = await supabase
    .from('tasks')
    .select('*')
    .eq('id', taskId)
    .single()

  // Initialize LLM with agent's persona
  const llm = new ChatOpenAI({
    modelName: "gpt-4",
    temperature: 0.7,
    openAIApiKey: Deno.env.get('OPENAI_API_KEY')
  })

  // Execute agent action
  const systemPrompt = `You are ${agent.name}, an AI agent with role: ${agent.role}.
  Your capabilities: ${agent.capabilities.join(', ')}.
  Execute tasks according to your role and capabilities.`

  const result = await llm.call([
    new SystemMessage(systemPrompt),
    new HumanMessage(`Execute action: ${action}\nTask: ${task.title}\nParameters: ${JSON.stringify(parameters)}`)
  ])

  // Update task with result
  await supabase
    .from('tasks')
    .update({
      status: 'completed',
      completed_at: new Date().toISOString(),
      result: { output: result.content }
    })
    .eq('id', taskId)

  return new Response(JSON.stringify({ success: true, result: result.content }), {
    headers: { 'Content-Type': 'application/json' }
  })
})
