```typescript
// supabase/functions/decision-engine/index.ts
import { serve } from "https://deno.land/std@0.168.0/http/server.ts"
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2'

interface Vote {
  agentId: string
  option: string
  reasoning: string
  confidence: number
}

serve(async (req) => {
  const supabase = createClient(
    Deno.env.get('SUPABASE_URL')!,
    Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
  )

  const { decisionId, vote } = await req.json() as { decisionId: string, vote: Vote }

  // Get current decision
  const { data: decision } = await supabase
    .from('decisions')
    .select('*')
    .eq('id', decisionId)
    .single()

  // Add vote
  const votes = decision.votes || {}
  votes[vote.agentId] = vote

  // Update decision
  await supabase
    .from('decisions')
    .update({ votes })
    .eq('id', decisionId)

  // Check if all agents have voted
  const { data: agents } = await supabase
    .from('agents')
    .select('id')
    .eq('organization_id', decision.organization_id)

  if (Object.keys(votes).length >= agents.length) {
    // Tally votes and determine result
    const result = tallyVotes(votes, decision.options)

    await supabase
      .from('decisions')
      .update({
        status: 'decided',
        result
      })
      .eq('id', decisionId)
  }

  return new Response(JSON.stringify({ success: true }), {
    headers: { 'Content-Type': 'application/json' }
  })
})

function tallyVotes(votes: Record<string, Vote>, options: any[]): any {
  const scores: Record<string, number> = {}

  for (const vote of Object.values(votes)) {
    if (!scores[vote.option]) scores[vote.option] = 0
    scores[vote.option] += vote.confidence
  }

  const winner = Object.entries(scores)
    .sort((a, b) => b[1] - a[1])[0]

  return {
    selectedOption: winner[0],
    totalScore: winner[1],
    voteBreakdown: scores
  }
}
