    this.apiKey = config.get('apiKey') || '';
  }

  async listTools(): Promise<MCPTool[]> {
    const response = await fetch(`${this.serverUrl}/tools/list`, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${this.apiKey}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({})
    });

    const data = await response.json();
    return data.tools;
  }

  async callTool(name: string, arguments_: object): Promise<MCPResponse> {
    const response = await fetch(`${this.serverUrl}/tools/call`, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${this.apiKey}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ name, arguments: arguments_ })
    });

    return response.json();
  }

  async getResource(uri: string): Promise<any> {
    const response = await fetch(`${this.serverUrl}/resources/read`, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${this.apiKey}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ uri })
    });

    return response.json();
  }
}
