import duckdb
import pandas as pd
from typing import List, Dict

class AnalyticsEngine:
    def __init__(self, database_path: str = ":memory:"):
        self.conn = duckdb.connect(database_path)

    def load_csv(self, table_name: str, csv_path: str):
        """Load CSV data into DuckDB table."""
        self.conn.execute(f"""
            CREATE TABLE IF NOT EXISTS {table_name} AS
            SELECT * FROM read_csv_auto('{csv_path}')
        """)

    def query(self, sql: str) -> pd.DataFrame:
        """Execute SQL query and return DataFrame."""
        return self.conn.execute(sql).fetchdf()

    def get_schema(self, table_name: str) -> List[Dict]:
        """Get table schema."""
        result = self.conn.execute(f"DESCRIBE {table_name}").fetchall()
        return [{"column": r[0], "type": r[1]} for r in result]

    def aggregate(self, table: str, group_by: str, metrics: List[str]) -> pd.DataFrame:
        """Perform aggregation."""
        metric_exprs = ", ".join([f"{m}({m.split('_')[0]}) as {m}" for m in metrics])

        sql = f"""
            SELECT {group_by}, {metric_exprs}
            FROM {table}
            GROUP BY {group_by}
            ORDER BY {group_by}
        """

        return self.query(sql)
