faq_1226.content:
**A:** Define custom workflows:

```javascript
// Create workflow
mcp__claude-flow__workflow_create({
  name: "code-review-workflow",
  steps: [
    { id: "analyze", agent: "code-analyzer", action: "analyze" },
    { id: "review", agent: "reviewer", action: "review", depends: ["analyze"] },
    { id: "test", agent: "tester", action: "test", depends: ["review"] },
    { id: "deploy", agent: "cicd-engineer", action: "deploy", depends: ["test"] }
  ],
  triggers: ["pull_request", "manual"]
})

// Execute workflow
mcp__claude-flow__workflow_execute({
  workflowId: "code-review-workflow",
  params: {
    repository: "my-repo",
    branch: "feature-branch"
  }
})
```

